            "type": "command",
            "command": "$HOME/.codex/hooks/atuin-history.sh",
            "timeout": 5,
            "async": true
          }
        ]
      }
    ],
    "UserPromptSubmit": [
      {
        "hooks": [
          {
            "type": "command",
            "command": "jq -c '{timestamp: (now | todate), prompt: .prompt[0:500]}' >> ~/.codex/prompt-history.jsonl",
            "timeout": 3,
            "async": true
          }
        ]
      }
    ],
    "Stop": [
      {
        "hooks": [
          {
            "type": "command",
            "command": "$HOME/.codex/hooks/notify.sh",
            "timeout": 3,
            "async": true
          },
          {
            "type": "command",
            "command": "$HOME/.codex/hooks/pushover.sh",
            "timeout": 6,
            "async": true
          }
        ]
      }
    ]
  }
}

